#!/usr/bin/env bash
#
# Publish the public API OpenAPI schema to this docs site.
#
# Source of truth: craftybase-app `docs/api/openapi.json`, generated by rswag
# (`RAILS_ENV=test bundle exec rake rswag:specs:swaggerize`). This script copies
# the latest committed schema into this repo, verifies the site still builds,
# commits, and pushes — which triggers the GitHub Pages deploy of api.stocksmith.dev.
#
# There is no CI mirror yet, so this is the manual sync step. Run it after the
# schema changes have merged in craftybase-app.
#
# Usage:
#   bin/sync-schema.sh                      # default source: ../craftybase-app/docs/api/openapi.json
#   bin/sync-schema.sh /path/to/openapi.json
#
set -euo pipefail
cd "$(dirname "$0")/.."

SRC="${1:-../craftybase-app/docs/api/openapi.json}"

if [ ! -f "$SRC" ]; then
  echo "ERROR: schema not found at: $SRC" >&2
  echo "Generate it first in craftybase-app:" >&2
  echo "  RAILS_ENV=test bundle exec rake rswag:specs:swaggerize" >&2
  exit 1
fi

cp "$SRC" openapi.json

# Verify the site builds with the new schema before publishing.
npm run build

if git diff --quiet -- openapi.json; then
  echo "Schema unchanged — nothing to publish."
  exit 0
fi

git add openapi.json
git commit -m "chore: sync openapi.json from craftybase-app"
git push origin main
echo "Published. GitHub Pages will redeploy api.stocksmith.dev shortly."
